import React, { useState, useMemo } from 'react';
import { Card, Button, Badge, Input, SectionTitle, Modal, ConfirmDialog, Select } from '../components/UI';
import { Search, Plus, LayoutGrid, Eye, Code, Edit2, List, Grid, Monitor, Trash2, FolderPlus, MoreVertical, Folder, AlertCircle } from 'lucide-react';
import { BUSINESS_TYPES, MOCK_COMPONENTS } from '../constants';
import { useGlobalContext } from '../GlobalContext';
import { BizLinePreview } from '../components/previews/BizLinePreview';
import { BizInetPreview } from '../components/previews/BizInetPreview';
import { BizIntranetPreview } from '../components/previews/BizIntranetPreview';
import { BizDialPreview } from '../components/previews/BizDialPreview';
import { BizCollectPreview } from '../components/previews/BizCollectPreview';
import { BizCompPreview } from '../components/previews/BizCompPreview';
import { Biz5GPreview } from '../components/previews/Biz5GPreview';
import { BizIdcPreview } from '../components/previews/BizIdcPreview';
import { BizBasePreview } from '../components/previews/BizBasePreview';
import { BizOtherPreview } from '../components/previews/BizOtherPreview';
import { GenericPreview } from '../components/previews/GenericPreview';
import { ComponentEditor } from '../components/ComponentEditor';

export const ComponentManager: React.FC = () => {
  const { mode, currentDomain } = useGlobalContext();

  // Data States
  // Initialize with remark and status fields
  const [components, setComponents] = useState(() => 
      MOCK_COMPONENTS.map(c => ({
          ...c,
          status: (c as any).status || 'published' 
      }))
  );

  const [categories, setCategories] = useState(BUSINESS_TYPES.map(b => ({ ...b, remark: '' })));

  // Filter States
  const [activeCategory, setActiveCategory] = useState<string>('all');
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | 'published' | 'draft'>('all');
  const [viewMode, setViewMode] = useState<'list' | 'grid-sm' | 'grid-lg'>('grid-lg');

  // Editor State
  const [editingComponent, setEditingComponent] = useState<any>(null);

  // Group Management State
  const [isGroupModalOpen, setIsGroupModalOpen] = useState(false);
  const [currentGroup, setCurrentGroup] = useState<{ name: string, code: string, remark: string, id?: string }>({ name: '', code: '', remark: '' });
  const [groupDeleteId, setGroupDeleteId] = useState<string | null>(null);
  const [groupDeleteWarning, setGroupDeleteWarning] = useState<string | null>(null);

  // Permission Logic: Filter allowed business types
  const allowedCategories = useMemo(() => {
    // If Super Domain (fusion), show everything from local state
    if (mode === 'fusion' || !currentDomain) {
      return categories;
    }
    // Filter categories based on domain's businessTypes
    return categories.filter(bt => 
      currentDomain.businessTypes.includes(bt.code) || bt.code === 'BIZ_BASE' || bt.code === 'BIZ_OTHER'
    );
  }, [mode, currentDomain, categories]);

  // 1. Get all components available to the current context (Permission filtered only)
  const allAccessibleComponents = useMemo(() => {
    let list = components;
    if (mode !== 'fusion' && currentDomain) {
        list = list.filter(c => 
            currentDomain.businessTypes.includes(c.category) || 
            c.category === 'BIZ_BASE' || 
            c.category === 'BIZ_OTHER'
        );
    }
    return list;
  }, [mode, currentDomain, components]);

  // 2. Filter components for display based on category, search, and status
  const filteredComponents = useMemo(() => {
    let list = allAccessibleComponents;

    // Category Filter
    if (activeCategory !== 'all') {
      list = list.filter(c => c.category === activeCategory);
    }

    // Status Filter
    if (statusFilter !== 'all') {
        list = list.filter(c => c.status === statusFilter);
    }

    // Search Filter
    if (search) {
      list = list.filter(c => c.name.toLowerCase().includes(search.toLowerCase()));
    }

    return list;
  }, [allAccessibleComponents, activeCategory, search, statusFilter]);

  // Helper to get count for a specific category within accessible components
  const getCategoryCount = (categoryCode: string) => {
      return allAccessibleComponents.filter(c => c.category === categoryCode).length;
  };

  // --- Render Preview Wrapper ---
  const renderPreview = (comp: any) => {
      switch (comp.category) {
        case 'BIZ_LINE': return <BizLinePreview comp={comp} />;
        case 'BIZ_INET': return <BizInetPreview comp={comp} />;
        case 'BIZ_INTRANET': return <BizIntranetPreview comp={comp} />;
        case 'BIZ_DIAL': return <BizDialPreview comp={comp} />;
        case 'BIZ_COLLECT': return <BizCollectPreview comp={comp} />;
        case 'BIZ_COMP': return <BizCompPreview comp={comp} />;
        case 'BIZ_5G': return <Biz5GPreview comp={comp} />;
        case 'BIZ_IDC': return <BizIdcPreview comp={comp} />;
        case 'BIZ_BASE': return <BizBasePreview comp={comp} />;
        case 'BIZ_OTHER': return <BizOtherPreview comp={comp} />;
        default: return <GenericPreview comp={comp} />;
      }
  };

  const getContainerClass = () => {
      switch (viewMode) {
          case 'list': return 'flex flex-col gap-3';
          case 'grid-sm': return 'grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-4';
          default: return 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4';
      }
  };

  // --- Component Actions ---
  const handleAddComponent = () => {
      setEditingComponent({
          name: '新建组件',
          category: activeCategory !== 'all' ? activeCategory : 'BIZ_BASE',
          type: 'chart',
          pluginType: 'Echarts',
          status: 'draft'
      });
  };

  const handleSaveComponent = (savedComp: any) => {
      if (savedComp.id) {
          // Update
          setComponents(prev => prev.map(c => c.id === savedComp.id ? savedComp : c));
      } else {
          // Add
          const newComp = { ...savedComp, id: `comp_${Date.now()}` };
          setComponents(prev => [newComp, ...prev]);
      }
      setEditingComponent(null);
  };

  // --- Group Actions ---
  const handleAddGroup = () => {
      setCurrentGroup({ name: '', code: '', remark: '' });
      setIsGroupModalOpen(true);
  };

  const handleEditGroup = (e: React.MouseEvent, group: any) => {
      e.stopPropagation();
      setCurrentGroup({ ...group, id: group.code, remark: group.remark || '' });
      setIsGroupModalOpen(true);
  };

  const handleDeleteGroupClick = (e: React.MouseEvent, code: string) => {
      e.stopPropagation();
      // Check if group has components
      const hasComponents = components.some(c => c.category === code);
      if (hasComponents) {
          setGroupDeleteWarning("该分组下存在组件，请先删除组件或移动组件后删除。");
          return;
      }
      setGroupDeleteId(code);
  };

  const confirmDeleteGroup = () => {
      if (groupDeleteId) {
          setCategories(prev => prev.filter(c => c.code !== groupDeleteId));
          if (activeCategory === groupDeleteId) setActiveCategory('all');
      }
      setGroupDeleteId(null);
  };

  const handleSaveGroup = () => {
      if (!currentGroup.name) return; // Validation

      const isEdit = !!currentGroup.id;

      if (isEdit) {
          setCategories(prev => prev.map(c => c.code === currentGroup.id ? { ...c, name: currentGroup.name, remark: currentGroup.remark } : c));
      } else {
          const newCode = `BIZ_${Date.now()}`;
          setCategories(prev => [...prev, { name: currentGroup.name, code: newCode, remark: currentGroup.remark }]);
      }
      setIsGroupModalOpen(false);
  };

  return (
    <div className="flex h-full gap-6">
      {/* Sidebar Categories */}
      <div className="w-64 flex flex-col gap-2 bg-slate-900/50 p-4 rounded-lg border border-slate-800">
        <div className="flex justify-between items-center mb-2">
            <SectionTitle title="组件列表" className="mb-0" />
            {mode === 'fusion' && (
                <button 
                    onClick={handleAddGroup}
                    className="p-1 hover:bg-slate-700 rounded text-slate-400 hover:text-white transition-colors" 
                    title="新建分组"
                >
                    <FolderPlus size={16} />
                </button>
            )}
        </div>

        <button 
          onClick={() => setActiveCategory('all')}
          className={`flex items-center justify-between px-3 py-2 rounded text-sm transition-all ${activeCategory === 'all' ? 'bg-blue-600 text-white shadow-md shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800'}`}
        >
          全部组件
          <Badge color={activeCategory === 'all' ? 'blue' : 'gray'}>
            {filteredComponents.length} / {allAccessibleComponents.length}
          </Badge>
        </button>
        <div className="h-px bg-slate-800 my-2" />
        <div className="flex-1 overflow-y-auto space-y-1 custom-scrollbar pr-1">
            {allowedCategories.map(cat => {
                const count = getCategoryCount(cat.code);
                const isActive = activeCategory === cat.code;
                return (
                    <div 
                        key={cat.code}
                        onClick={() => setActiveCategory(cat.code)}
                        className={`group relative w-full flex items-center justify-between px-3 py-2 rounded text-sm transition-all border cursor-pointer ${isActive ? 'bg-blue-600/10 text-blue-400 border-blue-500/50' : 'border-transparent text-slate-400 hover:bg-slate-800'}`}
                    >
                        <div className="flex items-center gap-2 truncate flex-1">
                            {isActive ? 
                                <div className="w-1.5 h-1.5 rounded-full bg-blue-500 shadow-[0_0_4px_#3b82f6]"></div> : 
                                <Folder size={14} className="text-slate-600" />
                            }
                            <span className="truncate">{cat.name}</span>
                        </div>
                        <span className={`text-[10px] px-1.5 py-0.5 rounded border min-w-[24px] text-center ${isActive ? 'text-blue-300 bg-blue-900/30 border-blue-800' : 'text-slate-600 bg-slate-800/50 border-slate-700/50'}`}>
                            {count}
                        </span>

                        {/* Hover Actions (Only in Fusion mode) */}
                        {mode === 'fusion' && (
                            <div className="absolute right-2 top-1/2 -translate-y-1/2 hidden group-hover:flex gap-1 bg-slate-900/90 rounded p-1 shadow-lg border border-slate-700 z-10">
                                <button 
                                    className="p-1 hover:text-blue-400 text-slate-400" 
                                    onClick={(e) => handleEditGroup(e, cat)}
                                    title="编辑分组"
                                >
                                    <Edit2 size={12} />
                                </button>
                                <button 
                                    className="p-1 hover:text-red-400 text-slate-400" 
                                    onClick={(e) => handleDeleteGroupClick(e, cat.code)}
                                    title="删除分组"
                                >
                                    <Trash2 size={12} />
                                </button>
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col gap-4 overflow-hidden">
        <Card className="shrink-0" bodyClassName="p-4">
          <div className="flex justify-between items-center">
             <div className="flex items-center gap-3">
                <div className="flex gap-2">
                    <Input 
                        placeholder="搜索组件名称..." 
                        className="w-48" 
                        value={search} 
                        onChange={e => setSearch(e.target.value)}
                        prefix={<Search size={16} />}
                    />
                    <Select 
                        options={[
                            {label: '全部状态', value: 'all'},
                            {label: '已发布', value: 'published'},
                            {label: '草稿', value: 'draft'}
                        ]}
                        value={statusFilter}
                        onChange={e => setStatusFilter(e.target.value as any)}
                        className="w-32"
                    />
                    <Button variant="secondary" icon={<Search size={16} />}>搜索</Button>
                </div>
             </div>

             <div className="flex items-center gap-4">
                 {mode === 'fusion' && (
                     <Button 
                        variant="primary" 
                        className="bg-emerald-600 hover:bg-emerald-500 text-white" 
                        icon={<Plus size={16}/>}
                        onClick={handleAddComponent}
                     >
                         添加组件
                     </Button>
                 )}
                 <div className="w-px h-6 bg-slate-700"></div>
                 <div className="flex bg-slate-800 rounded p-1 border border-slate-700">
                    <button 
                        onClick={() => setViewMode('list')} 
                        className={`p-1.5 rounded transition-colors ${viewMode === 'list' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                        title="列表视图"
                    >
                        <List size={16}/>
                    </button>
                    <button 
                        onClick={() => setViewMode('grid-sm')} 
                        className={`p-1.5 rounded transition-colors ${viewMode === 'grid-sm' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                        title="小图模式"
                    >
                        <Grid size={16}/>
                    </button>
                    <button 
                        onClick={() => setViewMode('grid-lg')} 
                        className={`p-1.5 rounded transition-colors ${viewMode === 'grid-lg' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}
                        title="大图模式"
                    >
                        <LayoutGrid size={16}/>
                    </button>
                 </div>
             </div>
          </div>
        </Card>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
          <div className={`${getContainerClass()} pb-4`}>
             {filteredComponents.map(comp => (
               <div 
                  key={comp.id} 
                  className={`
                      bg-[#0b1121] border border-slate-800 rounded-lg overflow-hidden hover:border-blue-500/50 hover:shadow-lg transition-all cursor-pointer group flex
                      ${viewMode === 'list' ? 'flex-row h-24 items-center' : 'flex-col'}
                      ${viewMode === 'grid-sm' ? 'h-[160px]' : ''}
                      ${viewMode === 'grid-lg' ? 'h-[220px]' : ''}
                  `}
                  onClick={() => setEditingComponent(comp)}
               >
                  {/* Visualization Area */}
                  <div className={`
                      bg-[#020617] relative border-slate-800/50 group-hover:bg-[#0f172a] transition-colors overflow-hidden shrink-0
                      ${viewMode === 'list' ? 'w-32 h-full border-r' : 'w-full border-b'}
                      ${viewMode === 'grid-sm' ? 'h-[100px]' : ''}
                      ${viewMode === 'grid-lg' ? 'h-[150px]' : ''}
                  `}>
                      {renderPreview(comp)}

                      {/* Status Badge */}
                      <div className={`absolute z-10 ${viewMode === 'list' ? 'top-1 left-1' : 'top-2 left-2'}`}>
                        <Badge color={comp.status === 'published' ? 'green' : 'yellow'} className="bg-black/50 backdrop-blur-sm border-0 text-[10px] scale-90">
                            {comp.status === 'published' ? '已发布' : '草稿'}
                        </Badge>
                      </div>

                      {/* Hover Overlay - ONLY SHOW IN GRID MODE */}
                      {viewMode !== 'list' && (
                          <div className="absolute inset-0 bg-black/40 backdrop-blur-[1px] opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2 z-20">
                               <Button size="sm" variant="primary" className="h-7 text-xs" icon={<Edit2 size={12}/>} onClick={(e) => { e.stopPropagation(); setEditingComponent(comp); }}>编辑</Button>
                          </div>
                      )}

                      {/* Type Badge */}
                      <div className={`absolute z-10 ${viewMode === 'list' ? 'hidden' : 'top-2 right-2'}`}>
                        <Badge color="gray" className="bg-black/50 backdrop-blur-sm border-0 text-[10px] scale-90 opacity-60 group-hover:opacity-100">{comp.type}</Badge>
                      </div>
                  </div>

                  {/* Info Area - Optimized for Layout */}
                  <div className={`flex-1 p-3 flex ${viewMode === 'list' ? 'items-center px-6' : 'flex-col justify-between'}`}>
                      {viewMode === 'list' ? (
                          <>
                            {/* Left: Title & ID */}
                            <div className="flex flex-col gap-1 min-w-[200px]">
                                <h4 className="text-slate-200 font-bold text-base truncate group-hover:text-blue-400 transition-colors" title={comp.name}>{comp.name}</h4>
                                <div className="flex items-center gap-2">
                                     <span className="text-[10px] text-slate-500 bg-slate-900 border border-slate-800 px-2 py-0.5 rounded font-mono select-all">{comp.id}</span>
                                </div>
                            </div>

                            {/* Center: Category */}
                            <div className="flex-1 flex justify-center">
                                 <div className="flex items-center gap-2 px-3 py-1 bg-slate-900/50 rounded-full border border-slate-800/50">
                                     <div className={`w-1.5 h-1.5 rounded-full ${['BIZ_5G', 'BIZ_COMP'].includes(comp.category) ? 'bg-purple-500' : (['BIZ_IDC'].includes(comp.category) ? 'bg-emerald-500' : 'bg-blue-500')}`}></div>
                                     <span className="text-xs text-slate-400">{categories.find(b => b.code === comp.category)?.name || comp.category}</span>
                                 </div>
                            </div>

                            {/* Right: Meta & Actions */}
                            <div className="flex items-center justify-end gap-6 min-w-[150px]">
                                <span className="text-xs text-slate-500">类型: <span className="text-slate-300">{comp.type}</span></span>
                                <Button size="sm" variant="ghost" className="opacity-0 group-hover:opacity-100 transition-opacity text-blue-400 hover:text-blue-300 hover:bg-blue-900/20" icon={<Edit2 size={14}/>}>配置</Button>
                            </div>
                          </>
                      ) : (
                          // Grid Layout (Keep simple)
                          <div className="flex-1 flex flex-col justify-between">
                            <div className="mb-1">
                                <h4 className="text-slate-200 font-bold text-sm truncate group-hover:text-blue-400 transition-colors" title={comp.name}>{comp.name}</h4>
                            </div>
                            <div className="flex items-center justify-between mt-auto">
                                 <div className="flex items-center gap-1.5">
                                     <div className={`w-1.5 h-1.5 rounded-full ${['BIZ_5G', 'BIZ_COMP'].includes(comp.category) ? 'bg-purple-500' : (['BIZ_IDC'].includes(comp.category) ? 'bg-emerald-500' : 'bg-blue-500')}`}></div>
                                     <span className="text-[10px] text-slate-500 uppercase">{categories.find(b => b.code === comp.category)?.name || comp.category}</span>
                                 </div>
                            </div>
                          </div>
                      )}
                  </div>
               </div>
             ))}
             {filteredComponents.length === 0 && (
               <div className="col-span-full py-20 flex flex-col items-center text-slate-600">
                  <LayoutGrid size={48} className="opacity-10 mb-4" />
                  <p>该分类下暂无可用组件或您没有相关业务权限</p>
               </div>
             )}
          </div>
        </div>
      </div>

      {/* Editor Overlay */}
      {editingComponent && (
          <ComponentEditor 
              component={editingComponent} 
              onClose={() => setEditingComponent(null)} 
              onSave={handleSaveComponent}
          />
      )}

      {/* Group Management Modal */}
      <Modal
          isOpen={isGroupModalOpen}
          onClose={() => setIsGroupModalOpen(false)}
          title={currentGroup.id ? "编辑分组" : "新增分组"}
          size="sm"
          footer={
              <>
                  <Button variant="secondary" onClick={() => setIsGroupModalOpen(false)}>取消</Button>
                  <Button onClick={handleSaveGroup}>确定</Button>
              </>
          }
      >
          <div className="space-y-4">
              <Input 
                  label="分组名称" 
                  value={currentGroup.name} 
                  onChange={e => setCurrentGroup({...currentGroup, name: e.target.value})}
                  placeholder="请输入分组名称"
              />
              <Input 
                  label="分组备注" 
                  value={currentGroup.remark} 
                  onChange={e => setCurrentGroup({...currentGroup, remark: e.target.value})}
                  placeholder="请输入备注信息"
              />
          </div>
      </Modal>

      <ConfirmDialog 
          isOpen={!!groupDeleteId} 
          title="删除分组"
          message="确定要删除该分组吗？删除后该分组下的组件可能无法正确显示。"
          onConfirm={confirmDeleteGroup}
          onCancel={() => setGroupDeleteId(null)}
      />

      {/* Warning Dialog */}
      <Modal
          isOpen={!!groupDeleteWarning}
          onClose={() => setGroupDeleteWarning(null)}
          title="无法删除"
          size="sm"
          footer={<Button onClick={() => setGroupDeleteWarning(null)}>确定</Button>}
      >
          <div className="flex items-center gap-3 py-4 text-slate-300">
              <div className="p-2 bg-amber-500/10 rounded-full text-amber-500 shrink-0">
                  <AlertCircle size={24} />
              </div>
              <p>{groupDeleteWarning}</p>
          </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Save, RotateCcw, ChevronDown, ChevronRight, Sliders, Maximize, Minimize } from 'lucide-react';
import { Button, Switch, Input } from './UI';
import { BizLinePreview } from './previews/BizLinePreview';
import { BizInetPreview } from './previews/BizInetPreview';
import { BizIntranetPreview } from './previews/BizIntranetPreview';
import { BizDialPreview } from './previews/BizDialPreview';
import { BizCollectPreview } from './previews/BizCollectPreview';
import { BizCompPreview } from './previews/BizCompPreview';
import { Biz5GPreview } from './previews/Biz5GPreview';
import { BizIdcPreview } from './previews/BizIdcPreview';
import { BizBasePreview } from './previews/BizBasePreview';
import { BizOtherPreview } from './previews/BizOtherPreview';
import { GenericPreview } from './previews/GenericPreview';
import { BUSINESS_TYPES } from '../constants';

const PLUGIN_TYPES = [
  'Echarts',
  '单张图片',
  '通用标题',
  '时间器',
  '跑马灯',
  '自定义背景框',
  '静态 MP4 播放器',
  'M3U8 视频流播放器',
  'iframe',
  '多行文本',
  '普通表格',
  '指标块',
  '自定义组件 wp',
  '地图插件',
  '复杂表格测试',
  '网络运营能力开放平台'
];

interface ComponentEditorProps {
  component: any;
  onClose: () => void;
  onSave: (component: any) => void;
}

const ConfigRow: React.FC<{ label: string; children?: React.ReactNode; className?: string }> = ({ label, children, className }) => (
  <div className={`flex items-center justify-between py-3 border-b border-slate-700/50 last:border-0 group ${className || ''}`}>
      <label className="text-sm text-slate-400 w-24 shrink-0">{label}</label>
      <div className="flex-1 px-2">
          {children}
      </div>
      <button className="text-slate-600 hover:text-blue-400 opacity-0 group-hover:opacity-100 transition-opacity p-1">
          <RotateCcw size={14} />
      </button>
  </div>
);

const CodeAreaRow: React.FC<{ label: string; value: string; onChange: (val: string) => void; placeholder?: string, height?: string }> = ({ label, value, onChange, placeholder, height = "h-24" }) => (
    <div className="py-2 border-b border-slate-700/50 last:border-0">
        <label className="text-sm text-slate-400 block mb-2">{label}:</label>
        <textarea 
            className={`w-full bg-[#0b1121] border border-blue-900/30 rounded p-2 text-xs font-mono text-blue-300 focus:border-blue-500 outline-none resize-none ${height}`}
            value={value}
            onChange={e => onChange(e.target.value)}
            placeholder={placeholder}
            spellCheck={false}
        />
    </div>
);

export const ComponentEditor: React.FC<ComponentEditorProps> = ({ component, onClose, onSave }) => {
  const isAddMode = !component.id;
  const [isBasicConfigOpen, setIsBasicConfigOpen] = useState(true);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // Component Meta State
  const [compMeta, setCompMeta] = useState({
      name: component.name,
      category: component.category,
      pluginType: component.pluginType || '网络运营能力开放平台', // Default if undefined
      type: component.type || 'chart',
      status: component.status || 'published'
  });

  // Config Form State (Visual)
  const [config, setConfig] = useState({
    defaultDim: '日',
    recentDays: '7',
    recentMonths: '6',
    color: 'rgba(255, 208, 0, 0.7)',
    isSmooth: true,
    chartType: component.type === 'chart' ? '散点图' : '默认',
  });

  // Developer Config State (For Add Mode)
  const [devConfig, setDevConfig] = useState({
      initMethod: '',
      configParams: `[\n  {\n    key: "$1",\n    label: "$柱子颜色",\n    type: "string",\n    value: "red",\n    enum: [\n      { key: "001", label: "上海" }\n    ]\n  }\n]`,
      callbackMethod: '',
      editMapping: false,
      callbackMapping: '{\n  xdata: "x轴数据"\n}',
      paramDesc: 'option = {\n\n}',
      initData: '[\n  {\n\n  }\n]'
  });

  // Sync state if component prop changes significantly (though unlikely in this modal lifecycle)
  useEffect(() => {
      setCompMeta({
          name: component.name,
          category: component.category,
          pluginType: component.pluginType || '网络运营能力开放平台',
          type: component.type || 'chart',
          status: component.status || 'published'
      });
  }, [component]);

  const categoryName = BUSINESS_TYPES.find(b => b.code === compMeta.category)?.name || compMeta.category;

  const handleSave = () => {
      const updatedComponent = {
          ...component,
          ...compMeta,
          // Merge custom config if we were persisting it
          devConfig: isAddMode ? devConfig : undefined
      };
      onSave(updatedComponent);
  };

  const renderPreview = () => {
      const previewProps = { comp: { ...component, ...compMeta } }; 
      switch (compMeta.category) {
        case 'BIZ_LINE': return <BizLinePreview {...previewProps} />;
        case 'BIZ_INET': return <BizInetPreview {...previewProps} />;
        case 'BIZ_INTRANET': return <BizIntranetPreview {...previewProps} />;
        case 'BIZ_DIAL': return <BizDialPreview {...previewProps} />;
        case 'BIZ_COLLECT': return <BizCollectPreview {...previewProps} />;
        case 'BIZ_COMP': return <BizCompPreview {...previewProps} />;
        case 'BIZ_5G': return <Biz5GPreview {...previewProps} />;
        case 'BIZ_IDC': return <BizIdcPreview {...previewProps} />;
        case 'BIZ_BASE': return <BizBasePreview {...previewProps} />;
        case 'BIZ_OTHER': return <BizOtherPreview {...previewProps} />;
        default: return <GenericPreview {...previewProps} />;
      }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/70 backdrop-blur-sm animate-in fade-in duration-200">
      <div className={`flex flex-col bg-[#020617] border border-slate-700 shadow-2xl transition-all duration-300 overflow-hidden ${isFullscreen ? 'w-full h-full rounded-none' : 'w-[80vw] h-[85vh] rounded-lg'}`}>

      {/* Header */}
      <div className="h-14 bg-[#0f172a] border-b border-slate-800 flex items-center justify-between px-6 shrink-0 shadow-md">
          <h2 className="text-lg font-bold text-blue-400 tracking-wide flex items-center gap-2">
              {component.id ? '编辑组件' : '新建组件'}
          </h2>
          <div className="flex items-center gap-4">
              <Button className="bg-emerald-500 hover:bg-emerald-600 text-white px-6" onClick={handleSave}>
                  保存
              </Button>
              <div className="w-px h-4 bg-slate-700 mx-1"></div>
              <button onClick={() => setIsFullscreen(!isFullscreen)} className="text-slate-400 hover:text-white transition-colors p-1 rounded hover:bg-slate-800">
                  {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
              </button>
              <button onClick={onClose} className="text-slate-400 hover:text-red-400 transition-colors p-1 rounded hover:bg-slate-800">
                  <X size={20} />
              </button>
          </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
          {/* Left Sidebar: Properties / Developer Config */}
          <div className="w-80 bg-[#1e293b]/50 border-r border-slate-800 flex flex-col">
              <div className="h-10 flex items-center px-4 bg-slate-800/50 border-b border-slate-700">
                  <span className="text-sm font-medium text-slate-200">{isAddMode ? '开发配置' : '属性设置'}</span>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar">

                  {isAddMode ? (
                      // --- Add Mode: Developer Config Fields ---
                      <div className="px-4 py-2 space-y-1">
                          <div className="py-2 border-b border-slate-700/50">
                              <ConfigRow label="发布状态">
                                  <div className="flex items-center gap-2">
                                      <Switch 
                                          checked={compMeta.status === 'published'} 
                                          onChange={c => setCompMeta({...compMeta, status: c ? 'published' : 'draft'})} 
                                      />
                                      <span className={`text-xs ${compMeta.status === 'published' ? 'text-green-400' : 'text-yellow-400'}`}>
                                          {compMeta.status === 'published' ? '已发布' : '草稿'}
                                      </span>
                                  </div>
                              </ConfigRow>
                          </div>
                          <CodeAreaRow 
                              label="初始化方法" 
                              value={devConfig.initMethod} 
                              onChange={v => setDevConfig({...devConfig, initMethod: v})} 
                              height="h-20"
                          />
                          <CodeAreaRow 
                              label="配置参数" 
                              value={devConfig.configParams} 
                              onChange={v => setDevConfig({...devConfig, configParams: v})} 
                              height="h-40"
                          />
                          <CodeAreaRow 
                              label="回调方法" 
                              value={devConfig.callbackMethod} 
                              onChange={v => setDevConfig({...devConfig, callbackMethod: v})} 
                              height="h-20"
                          />

                          <div className="flex items-center justify-between py-3 border-b border-slate-700/50">
                              <label className="text-sm text-slate-400">编辑映射:</label>
                              <div className="flex items-center gap-3">
                                  <span className={`text-xs ${!devConfig.editMapping ? 'text-blue-400 font-bold' : 'text-slate-500'}`}>否</span>
                                  <Switch checked={devConfig.editMapping} onChange={c => setDevConfig({...devConfig, editMapping: c})} />
                                  <span className={`text-xs ${devConfig.editMapping ? 'text-blue-400 font-bold' : 'text-slate-500'}`}>是</span>
                              </div>
                          </div>

                          <CodeAreaRow 
                              label="回调参数映射" 
                              value={devConfig.callbackMapping} 
                              onChange={v => setDevConfig({...devConfig, callbackMapping: v})} 
                              height="h-24"
                          />
                          <CodeAreaRow 
                              label="参数说明" 
                              value={devConfig.paramDesc} 
                              onChange={v => setDevConfig({...devConfig, paramDesc: v})} 
                              height="h-24"
                          />
                          <CodeAreaRow 
