                            <button onClick={() => setViewMode('grid-lg')} className={`p-1.5 rounded transition-colors ${viewMode === 'grid-lg' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}><LayoutGrid size={16}/></button>
